import api from './api';

export const getWallet = async () => {
  // Replace later
  return {
    balance: 120.5,
    transactions: [
      { id: 1, amount: 50, type: 'deposit', date: '2026-04-01' },
    ],
  };
};

export const addFunds = (amount) =>
  api.post('/wallet/add', { amount });

export const withdrawFunds = (amount, method) =>
  api.post('/wallet/withdraw', { amount, method });
